import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"The Agentic Loop","description":"","frontmatter":{"title":"The Agentic Loop","status":"complete"},"headers":[],"relativePath":"research/concepts/agentic-loop/index.md","filePath":"research/concepts/agentic-loop/index.md"}'),o={name:"research/concepts/agentic-loop/index.md"};function i(r,e,l,p,c,d){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-agentic-loop" tabindex="-1">The Agentic Loop <a class="header-anchor" href="#the-agentic-loop" aria-label="Permalink to &quot;The Agentic Loop&quot;">​</a></h1><p>Every coding agent — regardless of language, framework, or architecture — is built around the same primitive: a loop that alternates between <strong>thinking</strong> (LLM inference) and <strong>acting</strong> (tool execution). This document synthesizes the patterns, variations, and design decisions observed across 17+ real-world implementations.</p><hr><h2 id="core-pattern" tabindex="-1">Core Pattern <a class="header-anchor" href="#core-pattern" aria-label="Permalink to &quot;Core Pattern&quot;">​</a></h2><p>The agentic loop is a <strong>ReAct (Reasoning + Acting)</strong> cycle. The model receives context, decides what to do, the system executes that action, and the result feeds back as new context. This repeats until the model has nothing left to do.</p><h3 id="the-universal-pseudocode" tabindex="-1">The Universal Pseudocode <a class="header-anchor" href="#the-universal-pseudocode" aria-label="Permalink to &quot;The Universal Pseudocode&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>messages = [system_prompt, user_task]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while true:</span></span>
<span class="line"><span>    response = llm.generate(messages)</span></span>
<span class="line"><span>    messages.append(response)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    tool_calls = parse_tool_calls(response)</span></span>
<span class="line"><span>    if tool_calls is empty:</span></span>
<span class="line"><span>        break                          # model is done</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    for call in tool_calls:</span></span>
<span class="line"><span>        result = execute(call)</span></span>
<span class="line"><span>        messages.append(observation(result))</span></span></code></pre></div><p>This is not a simplification — it is the <strong>actual architecture</strong> of the simplest agents. mini-SWE-agent&#39;s entire step method is two lines:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> step</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">execute_actions</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">query</span><span style="color:#9399B2;">())</span></span></code></pre></div><p>Query the model, execute whatever it says. The entire agent is <code>~100 lines</code>. No planning step, no reflection step, no tool selection logic — just query → execute → append → repeat. And it scores competitively on SWE-bench.</p><h3 id="why-this-pattern-is-universal" tabindex="-1">Why This Pattern is Universal <a class="header-anchor" href="#why-this-pattern-is-universal" aria-label="Permalink to &quot;Why This Pattern is Universal&quot;">​</a></h3><p>Every agent we studied — from mini-SWE-agent&#39;s 100-line Python script to Codex CLI&#39;s thousands of lines of Rust — implements this same fundamental cycle. The reason is that it maps directly to how LLM APIs work:</p><ol><li><strong>LLMs are stateless functions</strong>: They take messages in and produce a response. The loop provides the statefulness.</li><li><strong>Tool use is the bridge</strong>: The model can&#39;t read files or run commands directly. Tool calls are the only way to affect the world.</li><li><strong>Observations close the loop</strong>: Without feeding results back, the model is flying blind. The loop is the feedback mechanism.</li><li><strong>Termination is natural</strong>: When the model has enough information and has completed its work, it simply responds with text instead of tool calls. No explicit &quot;stop&quot; signal is needed.</li></ol><p>The differences between agents — and they are substantial — emerge from what they layer <strong>around</strong> this core: how they manage state, when they stream, how they orchestrate multiple agents, and when they decide to stop.</p><hr><h2 id="variations" tabindex="-1">Variations <a class="header-anchor" href="#variations" aria-label="Permalink to &quot;Variations&quot;">​</a></h2><p>The agentic loop exists on a spectrum from minimal to highly orchestrated. Each variation adds capabilities but also complexity.</p><h3 id="the-spectrum" tabindex="-1">The Spectrum <a class="header-anchor" href="#the-spectrum" aria-label="Permalink to &quot;The Spectrum&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Simplest                                                          Most Complex</span></span>
<span class="line"><span>   │                                                                    │</span></span>
<span class="line"><span>   ▼                                                                    ▼</span></span>
<span class="line"><span>┌──────────┐  ┌──────────┐  ┌──────────┐  ┌──────────┐  ┌────────────┐</span></span>
<span class="line"><span>│  Simple  │  │ Streaming│  │  Event-  │  │ Message- │  │  Multi-    │</span></span>
<span class="line"><span>│  Linear  │  │   Loop   │  │  Driven  │  │ Passing  │  │  Agent     │</span></span>
<span class="line"><span>│          │  │          │  │  State   │  │  (SQ/EQ) │  │ Orchestr.  │</span></span>
<span class="line"><span>│mini-SWE  │  │ OpenCode │  │  Machine │  │          │  │            │</span></span>
<span class="line"><span>│  Pi      │  │  Goose   │  │          │  │  Codex   │  │ ForgeCode  │</span></span>
<span class="line"><span>│          │  │Gemini CLI│  │ OpenHands│  │          │  │ Ante       │</span></span>
<span class="line"><span>│          │  │          │  │          │  │          │  │ Claude Code│</span></span>
<span class="line"><span>└──────────┘  └──────────┘  └──────────┘  └──────────┘  └────────────┘</span></span>
<span class="line"><span>                                                              │</span></span>
<span class="line"><span>                                                    ┌─────────┴─────────┐</span></span>
<span class="line"><span>                                                    │  Edit-Apply-      │</span></span>
<span class="line"><span>                                                    │  Verify           │</span></span>
<span class="line"><span>                                                    │  (Aider, Junie)   │</span></span>
<span class="line"><span>                                                    │  [Orthogonal]     │</span></span>
<span class="line"><span>                                                    └───────────────────┘</span></span></code></pre></div><h3 id="_1-simple-linear-loop" tabindex="-1">1. Simple Linear Loop <a class="header-anchor" href="#_1-simple-linear-loop" aria-label="Permalink to &quot;1. Simple Linear Loop&quot;">​</a></h3><p><strong>Representatives</strong>: mini-SWE-agent, Pi</p><p>The purest form. A <code>while True</code> loop that calls the LLM, executes tool calls, appends results, and repeats. No streaming, no state machine, no message queues.</p><p><strong>Characteristics</strong>:</p><ul><li>Entire message history passed to LLM on every call</li><li>Synchronous execution — one tool call at a time</li><li>Termination by checking if the last message is an exit signal</li><li>No context management (messages go in, they never come out)</li></ul><p><strong>Strengths</strong>: Trivially debuggable. The trajectory saved to disk IS what the model saw. Perfect for research, fine-tuning, and RL — the trajectory is the training data.</p><p><strong>Limitations</strong>: Context window fills up on long tasks. No way to interrupt mid-generation. No real-time feedback to the user.</p><p>Pi takes this same minimal pattern and makes it extensible — the core loop stays simple, but extensions can hook into events (<code>tool:start</code>, <code>tool:complete</code>, <code>response:complete</code>) to add lint/test cycles, permission gates, or sub-agent delegation without touching the loop itself.</p><h3 id="_2-streaming-loop" tabindex="-1">2. Streaming Loop <a class="header-anchor" href="#_2-streaming-loop" aria-label="Permalink to &quot;2. Streaming Loop&quot;">​</a></h3><p><strong>Representatives</strong>: OpenCode (Go), Goose (Rust), Gemini CLI (TypeScript)</p><p>Adds token-by-token streaming to the basic loop. The LLM response is processed incrementally rather than waiting for completion, enabling real-time TUI rendering.</p><p><strong>Key difference from simple loop</strong>: The &quot;generate&quot; step becomes a stream processing pipeline:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>for event in provider.stream(messages):</span></span>
<span class="line"><span>    match event:</span></span>
<span class="line"><span>        TextDelta    → update display, accumulate text</span></span>
<span class="line"><span>        ToolUseStart → begin tracking new tool call</span></span>
<span class="line"><span>        ToolUseStop  → mark tool call complete</span></span>
<span class="line"><span>        Complete     → finalize message, track usage</span></span>
<span class="line"><span>        Error        → handle failure</span></span></code></pre></div><p><strong>OpenCode</strong> uses Go channels and context cancellation. Each streaming event immediately updates the message in the database and publishes via pub/sub, allowing the TUI to render in real time. Cancellation propagates through <code>context.Context</code> — the user presses Ctrl+X, the context cancels, and every layer (stream, tool execution, loop) checks <code>ctx.Done()</code>.</p><p><strong>Goose</strong> wraps its loop in <code>reply()</code> → <code>reply_internal()</code>, yielding an <code>AgentEvent</code> stream. Before each LLM call, it injects MOIM (Model-Oriented Information Management) context from extensions — dynamic per-turn information that keeps persistent instructions always present. Tool results are collected via <code>tokio::select!</code> that merges tool result streams with elicitation messages (polled every 100ms).</p><p><strong>Gemini CLI</strong> adds a <strong>tool scheduler</strong> between the model response and execution. When the model returns multiple tool calls, the scheduler batches read-only tools for parallel execution while sequencing mutating tools with confirmation gates. It also implements <strong>token caching</strong> — system instructions and tool declarations are cached server-side to reduce costs on long conversations.</p><h3 id="_3-event-driven-state-machine" tabindex="-1">3. Event-Driven State Machine <a class="header-anchor" href="#_3-event-driven-state-machine" aria-label="Permalink to &quot;3. Event-Driven State Machine&quot;">​</a></h3><p><strong>Representative</strong>: OpenHands</p><p>Replaces the simple loop with a formal state machine. An <code>AgentController</code> manages transitions between states (<code>INIT</code>, <code>RUNNING</code>, <code>PAUSED</code>, <code>AWAITING_USER_INPUT</code>, <code>FINISHED</code>, <code>ERROR</code>, <code>STOPPED</code>), and an <code>EventStream</code> acts as the central bus connecting controller, agent, runtime, and observers.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Controller._step():</span></span>
<span class="line"><span>    1. Check state, budget, iteration limits</span></span>
<span class="line"><span>    2. action = agent.step(state)</span></span>
<span class="line"><span>    3. Route action by type:</span></span>
<span class="line"><span>       - CondensationAction  → apply directly, re-step</span></span>
<span class="line"><span>       - AgentFinishAction   → transition to FINISHED</span></span>
<span class="line"><span>       - AgentDelegateAction → spawn child controller</span></span>
<span class="line"><span>       - MessageAction(wait) → transition to AWAITING_USER_INPUT</span></span>
<span class="line"><span>    4. Publish action to EventStream</span></span>
<span class="line"><span>    5. Run StuckDetector</span></span>
<span class="line"><span>    6. Runtime picks up action → executes → publishes Observation</span></span>
<span class="line"><span>    7. Next _step() sees Observation in state.history</span></span></code></pre></div><p><strong>What makes this different</strong>: Every action and every observation is a first-class <code>Event</code> in a persistent, append-only stream. Subscribers (runtime, security analyzer, logger, UI) independently react to events. The agent itself only sees conversation history and returns an <code>Action</code> — the controller handles all orchestration.</p><p><strong>Parallel tool calls</strong> are handled via a <code>pending_actions</code> queue: if the LLM returns 3 tool calls, they&#39;re queued and drained one per <code>_step()</code> call, without additional LLM calls until the queue is empty.</p><p><strong>Agent delegation</strong> uses a <code>NestedEventStore</code> — the child agent gets a filtered view of the parent&#39;s event stream, providing isolation while results flow back via <code>AgentDelegateObservation</code>.</p><h3 id="_4-message-passing-sq-eq" tabindex="-1">4. Message-Passing (SQ/EQ) <a class="header-anchor" href="#_4-message-passing-sq-eq" aria-label="Permalink to &quot;4. Message-Passing (SQ/EQ)&quot;">​</a></h3><p><strong>Representative</strong>: Codex CLI</p><p>Implements the loop as a Tokio task processing submissions from a <strong>Submission Queue (SQ)</strong> and emitting events to an <strong>Event Queue (EQ)</strong>. This decouples the loop from its callers entirely.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">while</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">submission</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> rx_sub</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">recv</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> submission</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">op </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">UserTurn</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;">    =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* build prompt, stream, process items */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ExecApproval</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* resolve blocked approval */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Compact</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;">      =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* run context compaction */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Interrupt</span><span style="color:#94E2D5;">           =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* cancel stream, abort tools */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Undo</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;">         =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* rollback last N turns */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Op</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Shutdown</span><span style="color:#94E2D5;">            =&gt;</span><span style="color:#CBA6F7;"> break</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>What makes this different</strong>: The loop processes not just &quot;run the next turn&quot; but a vocabulary of operations — approvals, compactions, interrupts, undos, sub-agent spawns. Each operation type is a distinct message. The UI is completely decoupled; it submits <code>Op</code>s and reads <code>Event</code>s.</p><p><strong>Tool execution</strong> is parallel by default when the model supports it (<code>futures::future::join_all</code>). The <code>ToolOrchestrator</code> handles the critical path: check approval → select sandbox → execute → handle sandbox denial with escalation retry.</p><p><strong>Auto-compaction</strong> triggers when estimated token usage hits 90% of the context window (default ~272K tokens), using a remote compaction endpoint that summarizes the conversation while preserving <code>GhostSnapshot</code> items for undo support.</p><h3 id="_5-multi-agent-orchestration" tabindex="-1">5. Multi-Agent Orchestration <a class="header-anchor" href="#_5-multi-agent-orchestration" aria-label="Permalink to &quot;5. Multi-Agent Orchestration&quot;">​</a></h3><p><strong>Representatives</strong>: ForgeCode (Forge/Muse/Sage), Ante, Claude Code, Capy</p><p>Instead of one agent running one loop, multiple specialized agents coordinate to complete a task. The variations differ in how they orchestrate:</p><p><strong>ForgeCode</strong> — Three named agents with distinct roles:</p><ul><li><strong>Muse</strong>: Read-only planning agent. High thinking budget. Produces implementation plans.</li><li><strong>Forge</strong>: Read-write execution agent. Low thinking budget during execution. Follows plans.</li><li><strong>Sage</strong>: Read-only research agent. Delegated to by Forge/Muse for deep codebase analysis.</li></ul><p>ForgeCode Services wraps these agents with: semantic entry-point discovery (before any agent runs), dynamic skill loading, tool-call correction (intercept and auto-fix before dispatch), progressive thinking policy (high budget for messages 1–10, low for 11+), and <strong>verification enforcement</strong> — the runtime programmatically requires a verification pass before marking any task complete. This was the key insight: prompting &quot;please verify&quot; doesn&#39;t reliably produce verification. Enforcement does.</p><p><strong>Ante</strong> — Two-tier fan-out/fan-in: a meta-agent decomposes tasks into sub-tasks, dispatches them to concurrent sub-agents (each running its own inner plan-act-observe loop), then synthesizes results. Built in Rust with a lock-free scheduler for genuine concurrency. Self-organizing philosophy: sub-agents adapt autonomously rather than requiring the meta-agent to micromanage.</p><p><strong>Claude Code</strong> — Three-phase loop (gather context → take action → verify) with sub-agent delegation. Sub-agents (Explore/Haiku for search, General-purpose/Sonnet for complex tasks) run in separate context windows. Key constraint: sub-agents cannot spawn sub-agents, preventing infinite nesting. The loop is not fixed-step — a simple question may need only one read; a complex bug fix cycles through all phases multiple times.</p><p><strong>Capy</strong> — Three-phase handoff: Captain (planning, can ask user clarifying questions, cannot write code) → Build (execution, cannot ask questions, works autonomously). Hard constraints on each phase create natural quality gates.</p><h3 id="_6-edit-apply-verify-loop" tabindex="-1">6. Edit-Apply-Verify Loop <a class="header-anchor" href="#_6-edit-apply-verify-loop" aria-label="Permalink to &quot;6. Edit-Apply-Verify Loop&quot;">​</a></h3><p><strong>Representatives</strong>: Aider, Junie CLI</p><p>An orthogonal pattern that can be layered onto any loop: after the LLM produces edits, the agent <strong>applies</strong> them, then <strong>verifies</strong> via lint and test, and iterates on failures.</p><p><strong>Aider</strong> — Human-directed single-turn edit cycle:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User message → Context assembly → LLM → Parse edits → Apply →</span></span>
<span class="line"><span>Git commit → Lint (if --auto-lint) → Test (if --auto-test) →</span></span>
<span class="line"><span>  └─ If errors: send to LLM → re-edit → re-apply → re-test</span></span></code></pre></div><p>The agent becomes &quot;agentic&quot; only in the lint/test feedback sub-loop — it autonomously iterates on failures with bounded retries. In <strong>architect mode</strong>, this splits into two models: a reasoning model (o3, R1) describes the solution in prose, then an editing model (Sonnet, GPT-4) translates it into structured file edits. Each model plays to its strengths.</p><p><strong>Junie CLI</strong> — Extends this with explicit phases (Understand → Plan → Implement → Verify → Diagnose) and dual execution paths. In IDE mode, implementation uses PSI-aware refactoring (semantically correct, all references updated, imports managed). In CLI mode, it falls back to text-based search-and-replace. Verification is first-class — not something the user must invoke, but an integral part of every task. Multi-model delegation routes sub-tasks to the most appropriate model (Flash for boilerplate, Sonnet for implementation, Opus for diagnosis).</p><h3 id="_7-dual-mode-and-specialized-loops" tabindex="-1">7. Dual-Mode and Specialized Loops <a class="header-anchor" href="#_7-dual-mode-and-specialized-loops" aria-label="Permalink to &quot;7. Dual-Mode and Specialized Loops&quot;">​</a></h3><p>Several agents implement mode-dependent loop behavior:</p><p><strong>Warp</strong> — Distinguished by Full Terminal Use (FTU). Because Warp owns the PTY, the agent can interact with live interactive processes (psql, vim, Python REPL). The agent reads the terminal buffer, writes input to the PTY, and monitors long-running processes. A takeover/handback pattern transfers control between human and agent at natural breakpoints.</p><p><strong>Droid</strong> — Delegation-oriented loop that works across interfaces (CLI, Slack, Linear, CI). Tracks an <strong>autonomy ratio</strong> (tool calls per user message, targeting 13x) as a key metric. Specification Mode separates planning (reasoning model) from execution (efficient model).</p><p><strong>SageAgent</strong> — Linear multi-agent pipeline: TaskAnalysis → Planning → Executor → Observation → TaskSummary, with a single feedback loop from Observation back to Planning when the task is incomplete.</p><h3 id="variation-comparison" tabindex="-1">Variation Comparison <a class="header-anchor" href="#variation-comparison" aria-label="Permalink to &quot;Variation Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variation</th><th>Complexity</th><th>Concurrency</th><th>Real-time UI</th><th>Error Recovery</th><th>Representative</th></tr></thead><tbody><tr><td>Simple linear</td><td>Minimal</td><td>None</td><td>No</td><td>Feed error to LLM</td><td>mini-SWE-agent</td></tr><tr><td>Streaming</td><td>Low</td><td>Async I/O</td><td>Yes</td><td>Feed error + retry</td><td>OpenCode</td></tr><tr><td>Event-driven SM</td><td>Medium</td><td>Event-based</td><td>Yes</td><td>Stuck detection + condensation</td><td>OpenHands</td></tr><tr><td>Message-passing</td><td>High</td><td>Full async</td><td>Yes</td><td>Interrupt + undo + compaction</td><td>Codex</td></tr><tr><td>Multi-agent</td><td>High</td><td>Sub-agent parallelism</td><td>Yes</td><td>Distributed recovery</td><td>ForgeCode</td></tr><tr><td>Edit-apply-verify</td><td>Medium</td><td>None</td><td>Partial</td><td>Lint/test retry loop</td><td>Aider</td></tr></tbody></table><hr><h2 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h2><p>How agents maintain context across loop iterations is a critical architectural decision. The approaches form a spectrum from trivially simple to highly structured.</p><h3 id="_1-linear-message-history" tabindex="-1">1. Linear Message History <a class="header-anchor" href="#_1-linear-message-history" aria-label="Permalink to &quot;1. Linear Message History&quot;">​</a></h3><p><strong>Used by</strong>: mini-SWE-agent, Pi</p><p>The simplest approach: a flat <code>list[dict]</code> where messages are appended and never removed.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> list</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;font-style:italic;">dict</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> =</span><span style="color:#9399B2;"> []</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Messages go in, they never come out</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> add_messages</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> *</span><span style="color:#EBA0AC;font-style:italic;">messages</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">extend</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Advantage</strong>: The trajectory IS the state. Perfect reproducibility — replay the same messages and you get the same behavior. Ideal for research and fine-tuning.</p><p><strong>Limitation</strong>: No context management. Long tasks exhaust the context window. mini-SWE-agent&#39;s typical SWE-bench trajectory is ~20-40 steps — short enough that this works, but it doesn&#39;t scale to longer sessions.</p><h3 id="_2-conversation-objects-with-metadata" tabindex="-1">2. Conversation Objects with Metadata <a class="header-anchor" href="#_2-conversation-objects-with-metadata" aria-label="Permalink to &quot;2. Conversation Objects with Metadata&quot;">​</a></h3><p><strong>Used by</strong>: OpenCode, Goose, Gemini CLI, most production agents</p><p>Messages are wrapped in structured objects with metadata (model, finish reason, token usage, timestamps). The conversation is persisted to a database or file system.</p><p>OpenCode persists every message to a database and publishes updates via pub/sub. When the session has a summary, it truncates history to the summary message and re-roles it as a &quot;user&quot; message — effectively restarting the conversation from the summary while preserving context.</p><p>Goose tracks messages with visibility flags — messages marked invisible by summarization are excluded from LLM calls but preserved in the session. A <code>tool_call_cut_off</code> determines where old tool-call pairs should be summarized in the background.</p><h3 id="_3-event-streams-with-action-observation-pairs" tabindex="-1">3. Event Streams with Action/Observation Pairs <a class="header-anchor" href="#_3-event-streams-with-action-observation-pairs" aria-label="Permalink to &quot;3. Event Streams with Action/Observation Pairs&quot;">​</a></h3><p><strong>Used by</strong>: OpenHands</p><p>State is an append-only <code>EventStream</code> of typed events. Each action (what the agent wants to do) and observation (what happened) is a discrete event with metadata (source, timestamp, cause).</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>EventStream: [UserMsg₀, CmdRun₁, CmdOutput₂, FileEdit₃, FileEditObs₄, ...]</span></span></code></pre></div><p>The agent sees a <strong>projected view</strong> of this stream (the <code>State</code> object), not the raw events. This enables:</p><ul><li><strong>Condensation</strong>: Old events can be summarized without destroying the original stream</li><li><strong>Delegation</strong>: Child agents get a filtered view via <code>NestedEventStore</code></li><li><strong>Replay</strong>: The stream can be replayed to reconstruct state</li><li><strong>Observation</strong>: External systems can subscribe to the stream for monitoring</li></ul><h3 id="_4-structured-session-state-with-checkpointing" tabindex="-1">4. Structured Session State with Checkpointing <a class="header-anchor" href="#_4-structured-session-state-with-checkpointing" aria-label="Permalink to &quot;4. Structured Session State with Checkpointing&quot;">​</a></h3><p><strong>Used by</strong>: Codex CLI, Claude Code</p><p>Codex&#39;s <code>ContextManager</code> maintains a structured item list (<code>Vec&lt;ResponseItem&gt;</code>) with operations for compaction, undo, and rollback. <code>GhostSnapshot</code> items are preserved across compaction and undo, enabling redo. Sessions are persisted as JSONL rollouts that can be resumed across terminal restarts.</p><p>Claude Code adds <strong>checkpoints</strong> that capture both conversation state and code state. Users can rewind to any checkpoint, restoring conversation, files, or both. Checkpoints persist across sessions.</p><h3 id="_5-multi-agent-shared-state" tabindex="-1">5. Multi-Agent Shared State <a class="header-anchor" href="#_5-multi-agent-shared-state" aria-label="Permalink to &quot;5. Multi-Agent Shared State&quot;">​</a></h3><p><strong>Used by</strong>: ForgeCode, Ante, Capy</p><p>When multiple agents collaborate, state management must handle cross-agent coordination:</p><p>ForgeCode preserves context across agent switches (Muse → Forge → Sage) while keeping each agent&#39;s internal working context bounded. The <code>todo_write</code> tool provides explicit shared state — each agent reads and updates the same task list.</p><p>Ante&#39;s sub-agents have independent contexts (each with a focused, smaller window) but share results through the meta-agent&#39;s fan-in step. This prevents context window exhaustion that would occur if all sub-task context were in one window.</p><p>Capy enforces strict isolation: Captain&#39;s output (the spec) is the sole interface to Build. No shared mutable state, no mid-execution communication.</p><h3 id="state-management-comparison" tabindex="-1">State Management Comparison <a class="header-anchor" href="#state-management-comparison" aria-label="Permalink to &quot;State Management Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Context Control</th><th>Reproducibility</th><th>Multi-Agent</th><th>Persistence</th></tr></thead><tbody><tr><td>Linear list</td><td>None (grow only)</td><td>Perfect</td><td>N/A</td><td>Trajectory file</td></tr><tr><td>Conversation + metadata</td><td>Summarization</td><td>Good</td><td>Shared DB</td><td>Database</td></tr><tr><td>Event stream</td><td>Condensation</td><td>Perfect (replay)</td><td>NestedEventStore</td><td>Append-only log</td></tr><tr><td>Structured + checkpoints</td><td>Compaction + undo</td><td>Good (rollout)</td><td>Sub-agent sessions</td><td>JSONL rollout</td></tr><tr><td>Multi-agent shared</td><td>Per-agent bounded</td><td>Partial</td><td>Explicit interfaces</td><td>Per-session</td></tr></tbody></table><hr><h2 id="stop-conditions" tabindex="-1">Stop Conditions <a class="header-anchor" href="#stop-conditions" aria-label="Permalink to &quot;Stop Conditions&quot;">​</a></h2><p>The loop must terminate. Agents employ a layered approach — multiple independent conditions, any of which can halt execution.</p><h3 id="_1-model-signals-completion" tabindex="-1">1. Model Signals Completion <a class="header-anchor" href="#_1-model-signals-completion" aria-label="Permalink to &quot;1. Model Signals Completion&quot;">​</a></h3><p>The most natural termination: the LLM responds with text and <strong>no tool calls</strong>. This means it has nothing left to do.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># Every agent checks this</span></span>
<span class="line"><span>if response.tool_calls is empty:</span></span>
<span class="line"><span>    break  # model is done</span></span></code></pre></div><p>Variants:</p><ul><li>mini-SWE-agent: checks <code>messages[-1].role == &quot;exit&quot;</code> (the model outputs a special submit command)</li><li>OpenCode: checks <code>FinishReason == EndTurn</code> (not <code>ToolUse</code>)</li><li>Goose: text-only response → exit the loop</li><li>Codex: <code>!session.has_pending_tool_results()</code> → emit <code>TurnComplete</code></li><li>OpenHands: agent returns <code>AgentFinishAction</code> → controller transitions to <code>FINISHED</code></li></ul><p>This is the <strong>only universal</strong> stop condition — every agent implements it. All others are safety nets.</p><h3 id="_2-iteration-token-budget-limits" tabindex="-1">2. Iteration / Token Budget Limits <a class="header-anchor" href="#_2-iteration-token-budget-limits" aria-label="Permalink to &quot;2. Iteration / Token Budget Limits&quot;">​</a></h3><p>Hard caps to prevent runaway loops:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Iteration Limit</th><th>Budget Limit</th></tr></thead><tbody><tr><td>mini-SWE-agent</td><td><code>step_limit</code> (configurable)</td><td><code>cost_limit</code> ($3.00 default)</td></tr><tr><td>OpenHands</td><td><code>max_iterations</code> per run</td><td>Per-task budget</td></tr><tr><td>Goose</td><td><code>max_turns</code> (1000 default, via <code>GOOSE_MAX_TURNS</code>)</td><td>—</td></tr><tr><td>Gemini CLI</td><td>Max iterations per turn + timeout</td><td>Token budget exhaustion</td></tr><tr><td>Junie</td><td>3–5 implement-verify cycles</td><td>Token + time budget</td></tr><tr><td>ForgeCode</td><td><code>max_requests_per_turn</code></td><td><code>FORGE_TOOL_TIMEOUT</code> (300s)</td></tr><tr><td>Codex</td><td>— (no explicit turn limit)</td><td>Auto-compaction at 90% window</td></tr></tbody></table><p>OpenCode notably has <strong>no explicit turn limit</strong> — it trusts the model to know when to stop. This is a deliberate design choice with trade-offs.</p><h3 id="_3-user-interrupt" tabindex="-1">3. User Interrupt <a class="header-anchor" href="#_3-user-interrupt" aria-label="Permalink to &quot;3. User Interrupt&quot;">​</a></h3><p>Every interactive agent supports interruption, but the mechanisms differ:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Mechanism</th><th>Behavior</th></tr></thead><tbody><tr><td>OpenCode</td><td><code>Cancel(sessionID)</code> → context cancellation</td><td>Clean abort at next check point</td></tr><tr><td>Claude Code</td><td><code>Esc</code> key</td><td>Stop mid-action, context preserved, redirect</td></tr><tr><td>Goose</td><td><code>CancellationToken</code></td><td>Checked at loop top and during tool collection</td></tr><tr><td>Codex</td><td><code>Op::Interrupt</code> → cancel stream + abort tools</td><td>Double Ctrl+C exits program</td></tr><tr><td>Warp</td><td>Handback pattern</td><td>Agent signals completion at natural breakpoints</td></tr></tbody></table><p>Claude Code&#39;s approach is notable: the user can <strong>type while Claude works</strong> — Claude sees the message and adjusts approach. No need to wait for completion.</p><h3 id="_4-error-accumulation" tabindex="-1">4. Error Accumulation <a class="header-anchor" href="#_4-error-accumulation" aria-label="Permalink to &quot;4. Error Accumulation&quot;">​</a></h3><p>Rather than failing on a single error, agents can tolerate errors up to a threshold:</p><ul><li><strong>ForgeCode</strong>: <code>max_tool_failure_per_turn</code> — limits consecutive tool failures before forcing completion, preventing infinite retry loops</li><li><strong>OpenHands</strong>: Error loop detection in StuckDetector — if last K observations are all <code>ErrorObservation</code>, the agent is stuck</li><li><strong>Goose</strong>: <code>ContextLengthExceeded</code> triggers compaction (up to 2 attempts), then gives up</li></ul><h3 id="_5-stuck-detection" tabindex="-1">5. Stuck Detection <a class="header-anchor" href="#_5-stuck-detection" aria-label="Permalink to &quot;5. Stuck Detection&quot;">​</a></h3><p><strong>OpenHands&#39; StuckDetector</strong> is the most sophisticated approach, running after every step:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Pattern</th><th>Detection</th></tr></thead><tbody><tr><td>Identical repetition</td><td><code>action[n] == action[n-1] == action[n-2]</code></td><td>Same action 3x in a row</td></tr><tr><td>Alternating pattern</td><td><code>action[n] == action[n-2] &amp;&amp; action[n-1] == action[n-3]</code></td><td>Ping-ponging between two actions</td></tr><tr><td>Error loop</td><td>Last K observations are all errors</td><td>Repeated errors without recovery</td></tr><tr><td>Empty response</td><td>Last K actions have empty content</td><td>Degenerate LLM output</td></tr></tbody></table><p>Recovery options: raise <code>AgentStuckInLoopError</code> (terminate), inject <code>LoopRecoveryAction</code> (nudge), or force condensation (compress history to break the pattern).</p><p><strong>Goose&#39;s RepetitionInspector</strong> serves a similar function — it detects tools called repeatedly without progress and can block further calls.</p><h3 id="_6-verification-pass" tabindex="-1">6. Verification Pass <a class="header-anchor" href="#_6-verification-pass" aria-label="Permalink to &quot;6. Verification Pass&quot;">​</a></h3><p>Some agents require explicit verification before allowing completion:</p><p><strong>ForgeCode</strong>: The runtime <strong>programmatically enforces</strong> a verification pass. Before a task is marked complete, it checks whether the agent called the verification skill. If not, the runtime injects a reminder and requires it — no opt-out. The verification generates a checklist: what was requested, what was done, what evidence exists, what&#39;s missing. This was the key insight from TermBench evaluation — models under pressure skip optional verification.</p><p><strong>Aider</strong>: The lint/test cycle after applying edits serves as implicit verification. If <code>--auto-test</code> is enabled and tests fail, the agent iterates (with bounded retries) before presenting results.</p><p><strong>Junie</strong>: Verification is first-class. After implementation, the agent runs tests, checks inspections, validates compilation. If failures are found, it enters a diagnostic loop (analyze → fix → re-verify) for up to 3–5 iterations before escalating.</p><h3 id="stop-condition-layering" tabindex="-1">Stop Condition Layering <a class="header-anchor" href="#stop-condition-layering" aria-label="Permalink to &quot;Stop Condition Layering&quot;">​</a></h3><p>In practice, agents use multiple conditions simultaneously:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>while true:</span></span>
<span class="line"><span>    if cancelled:           break    # User interrupt</span></span>
<span class="line"><span>    if iterations &gt; max:    break    # Safety cap</span></span>
<span class="line"><span>    if budget_exceeded:     break    # Cost control</span></span>
<span class="line"><span>    if stuck_detected:      break    # Pattern detection</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    response = llm.generate(messages)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    if no_tool_calls(response):</span></span>
<span class="line"><span>        if verification_required and not verified:</span></span>
<span class="line"><span>            inject_verification_prompt()</span></span>
<span class="line"><span>            continue</span></span>
<span class="line"><span>        break                        # Natural completion</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    execute_tools(response)</span></span></code></pre></div><p>The order matters: user interrupt takes highest priority, then resource limits, then stuck detection, then natural completion with optional verification enforcement.</p><h2 id="tools-projects" tabindex="-1">Tools &amp; Projects <a class="header-anchor" href="#tools-projects" aria-label="Permalink to &quot;Tools &amp; Projects&quot;">​</a></h2><p>This section surveys the key frameworks, protocols, benchmarks, and observability tools relevant to building and evaluating agentic loops in coding agents. For deep dives on each tool, see the <a href="./../../.copilot/session-state/d0354d87-4da1-4c93-a043-006f84879a18/files/agentic-loop-tools.html">full research file</a>.</p><h3 id="agent-frameworks" tabindex="-1">Agent Frameworks <a class="header-anchor" href="#agent-frameworks" aria-label="Permalink to &quot;Agent Frameworks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Language</th><th>Paradigm</th><th>Key Differentiator</th></tr></thead><tbody><tr><td><strong>LangGraph</strong></td><td>Python, JS/TS</td><td>Graph-based state machines</td><td>Checkpointing, time-travel debugging, durable execution</td></tr><tr><td><strong>CrewAI</strong></td><td>Python</td><td>Role-based crews + flows</td><td>YAML-configured agent teams with sequential/hierarchical processes</td></tr><tr><td><strong>AutoGen</strong></td><td>Python, .NET</td><td>Multi-agent conversation</td><td>Agents as tools, group chat, AutoGen Studio GUI</td></tr><tr><td><strong>Smolagents</strong></td><td>Python</td><td>Code-as-action ReAct</td><td>LLM writes Python as actions — 30% fewer steps than JSON tool-calling</td></tr><tr><td><strong>PydanticAI</strong></td><td>Python</td><td>Type-safe agents</td><td><code>Agent[DepsType, OutputType]</code> generics, dependency injection, Pydantic validation</td></tr><tr><td><strong>Mastra</strong></td><td>TypeScript</td><td>Workflow + agents</td><td><code>.then()/.branch()/.parallel()</code> chainable syntax, React/Next.js integration</td></tr><tr><td><strong>OpenAI Agents SDK</strong></td><td>Python</td><td>Handoff chains</td><td>Minimal abstractions, guardrails, built-in tracing; production successor to Swarm</td></tr><tr><td><strong>Google ADK</strong></td><td>Python, Java, Go</td><td>Hierarchical multi-agent</td><td>Session rewind, <code>adk eval</code> CLI, code execution sandbox, A2A native</td></tr></tbody></table><ul><li><strong>LangGraph</strong> — Low-level orchestration modeling agents as cyclic graphs (nodes = steps, edges = transitions). Supports checkpointing, time-travel debugging, and subgraph composition. <a href="https://github.com/langchain-ai/langgraph" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langgraph</a> — Ideal for coding agents needing plan→code→test→debug loops with failure recovery.</li><li><strong>CrewAI</strong> — Multi-agent framework where &quot;crews&quot; of role-based agents collaborate on tasks. Crews handle autonomous collaboration; Flows add deterministic, event-driven control. <a href="https://github.com/crewAIInc/crewAI" target="_blank" rel="noreferrer">https://github.com/crewAIInc/crewAI</a> — Maps naturally to planner/coder/reviewer/tester agent teams.</li><li><strong>AutoGen</strong> — Microsoft&#39;s layered multi-agent framework with Core, AgentChat, and Extensions APIs. The <code>AgentTool</code> pattern wraps agents as callable tools for hierarchical setups. <a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a> — Enables coding agents that discuss and refine code through multi-turn dialogue.</li><li><strong>Smolagents</strong> — Hugging Face&#39;s minimal library (~1,000 LOC) where the CodeAgent writes executable Python as its action rather than JSON tool specs. <a href="https://github.com/huggingface/smolagents" target="_blank" rel="noreferrer">https://github.com/huggingface/smolagents</a> — The most directly relevant paradigm for coding agents; code-as-action mirrors what coding agents actually do.</li><li><strong>PydanticAI</strong> — Type-safe agent framework bringing the &quot;FastAPI feeling&quot; to GenAI. Agents are generic types with dependency injection and automatic output validation. <a href="https://github.com/pydantic/pydantic-ai" target="_blank" rel="noreferrer">https://github.com/pydantic/pydantic-ai</a> — Excellent for agents needing reliable structured outputs (diffs, AST edits, test results).</li><li><strong>Mastra</strong> — TypeScript-first framework for the JS/Node ecosystem with intuitive workflow chaining and suspend/resume. <a href="https://github.com/mastra-ai/mastra" target="_blank" rel="noreferrer">https://github.com/mastra-ai/mastra</a> — Primary option for building coding agents in TypeScript.</li><li><strong>OpenAI Agents SDK</strong> — Lightweight, production-ready evolution of Swarm. Core loop: get completion → execute tools → handle handoffs → repeat. <a href="https://github.com/openai/openai-agents-python" target="_blank" rel="noreferrer">https://github.com/openai/openai-agents-python</a> — Clean handoff pattern routes coding tasks to specialist sub-agents.</li><li><strong>Google ADK</strong> — Code-first framework optimized for Gemini but model-agnostic. Hierarchical multi-agent with parent→child routing and session rewind. <a href="https://github.com/google/adk-python" target="_blank" rel="noreferrer">https://github.com/google/adk-python</a> — Session rewind is uniquely valuable for debugging agent trajectories.</li></ul><h3 id="multi-agent-protocols" tabindex="-1">Multi-Agent Protocols <a class="header-anchor" href="#multi-agent-protocols" aria-label="Permalink to &quot;Multi-Agent Protocols&quot;">​</a></h3><ul><li><strong>Swarm</strong> — OpenAI&#39;s experimental (now deprecated) framework that introduced the <strong>handoff</strong> pattern: an agent delegates by returning another agent from a function. Stateless between calls. <a href="https://github.com/openai/swarm" target="_blank" rel="noreferrer">https://github.com/openai/swarm</a> — Established the handoff pattern now standard in the OpenAI Agents SDK.</li><li><strong>A2A (Agent-to-Agent)</strong> — Google-contributed open protocol (under Linux Foundation) for communication between opaque agents. Uses Agent Cards for discovery and JSON-RPC 2.0 over HTTP(S). <a href="https://github.com/a2aproject/A2A" target="_blank" rel="noreferrer">https://github.com/a2aproject/A2A</a> — Enables heterogeneous agent ecosystems (e.g., a LangGraph coding agent delegating to a CrewAI testing agent). Complements MCP: MCP = agent-to-tool, A2A = agent-to-agent.</li></ul><h3 id="benchmarks-evaluation" tabindex="-1">Benchmarks &amp; Evaluation <a class="header-anchor" href="#benchmarks-evaluation" aria-label="Permalink to &quot;Benchmarks &amp; Evaluation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Focus</th><th>Scale</th><th>Why It Matters</th></tr></thead><tbody><tr><td><strong>SWE-bench</strong></td><td>Real GitHub issue resolution</td><td>2,294 tasks (500 verified)</td><td>Gold-standard for coding agents — tests the full agentic loop</td></tr><tr><td><strong>Terminal-Bench</strong></td><td>Terminal/CLI agent tasks</td><td>—</td><td>Tests command-line navigation and system administration</td></tr><tr><td><strong>AgentBench</strong></td><td>Multi-environment (OS, DB, web)</td><td>8 environments</td><td>Broadest coverage — OS interaction and DB tasks are coding-adjacent</td></tr></tbody></table><ul><li><strong>SWE-bench</strong> — The definitive coding agent benchmark. Agents receive a real codebase + issue description and must produce a working patch. Variants include Verified (500 human-vetted problems), Multimodal, and Multilingual. Current SOTA: ~74% on Verified. <a href="https://swebench.com" target="_blank" rel="noreferrer">https://swebench.com</a> — Tests understanding, navigation, code generation, and test-passing in one benchmark.</li><li><strong>Terminal-Bench</strong> — Benchmark focused on terminal and CLI tasks, testing an agent&#39;s ability to navigate file systems, run commands, and solve system-level problems. Relevant for coding agents that operate primarily through shell interfaces.</li><li><strong>AgentBench</strong> — First multi-environment agent benchmark (Tsinghua). Tests LLM-as-Agent across OS interaction, databases, knowledge graphs, web browsing, and more. <a href="https://github.com/THUDM/AgentBench" target="_blank" rel="noreferrer">https://github.com/THUDM/AgentBench</a> — The OS and DB tasks directly test capabilities coding agents need beyond pure code generation.</li></ul><h3 id="observability-debugging" tabindex="-1">Observability &amp; Debugging <a class="header-anchor" href="#observability-debugging" aria-label="Permalink to &quot;Observability &amp; Debugging&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Open Source</th><th>OTel-Based</th><th>Multi-Framework</th><th>Best For</th></tr></thead><tbody><tr><td><strong>LangSmith</strong></td><td>SDK only</td><td>No</td><td>LangChain/LangGraph</td><td>Full-lifecycle LLM observability with evals</td></tr><tr><td><strong>Phoenix (Arize)</strong></td><td>Yes</td><td>Yes</td><td>15+ integrations</td><td>Vendor-agnostic tracing and evaluation</td></tr><tr><td><strong>Logfire (Pydantic)</strong></td><td>No</td><td>Yes</td><td>PydanticAI-focused</td><td>Real-time debugging with Pydantic integration</td></tr></tbody></table><ul><li><strong>LangSmith</strong> — Full-lifecycle observability platform: trace, debug, evaluate, and monitor agents. Uses <code>@traceable</code> decorator for automatic instrumentation. <a href="https://github.com/langchain-ai/langsmith-sdk" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langsmith-sdk</a> — Essential for understanding agent decisions in LangGraph-based coding agents.</li><li><strong>Phoenix (Arize)</strong> — Open-source AI observability built on OpenTelemetry via OpenInference. Supports OpenAI Agents SDK, LangGraph, CrewAI, Mastra, and many more. <a href="https://github.com/Arize-ai/phoenix" target="_blank" rel="noreferrer">https://github.com/Arize-ai/phoenix</a> — The leading open-source alternative to LangSmith; vendor-agnostic approach works with any agent framework.</li><li><strong>Logfire (Pydantic)</strong> — OpenTelemetry-based observability with deep PydanticAI integration. Real-time debugging, behavior tracing, and cost tracking. <a href="https://pydantic.dev/logfire" target="_blank" rel="noreferrer">https://pydantic.dev/logfire</a> — Tight integration makes it the natural choice for PydanticAI-based coding agents.</li></ul><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Loop Style</th><th>Reference</th></tr></thead><tbody><tr><td><strong>mini-SWE-agent</strong></td><td>Simplest loop (~100 lines), ReAct with bash-only tooling</td><td><a href="./../agents/mini-swe-agent/agentic-loop.html"><code>../agents/mini-swe-agent/agentic-loop.md</code></a></td></tr><tr><td><strong>opencode</strong></td><td>Go agentic loop with streaming support and cancellation</td><td><a href="./../agents/opencode/agentic-loop.html"><code>../agents/opencode/agentic-loop.md</code></a></td></tr><tr><td><strong>OpenHands</strong></td><td>Event-driven state machine loop</td><td><a href="./../agents/openhands/agentic-loop.html"><code>../agents/openhands/agentic-loop.md</code></a></td></tr><tr><td><strong>Codex</strong></td><td>SQ/EQ message-passing loop implemented in Rust</td><td><a href="./../agents/codex/agentic-loop.html"><code>../agents/codex/agentic-loop.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td>Three-phase loop with sub-agent delegation</td><td><a href="./../agents/claude-code/agentic-loop.html"><code>../agents/claude-code/agentic-loop.md</code></a></td></tr><tr><td><strong>ForgeCode</strong></td><td>Multi-agent orchestration (Forge/Muse/Sage)</td><td><a href="./../agents/forgecode/agentic-loop.html"><code>../agents/forgecode/agentic-loop.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td><code>reply()</code> → <code>reply_internal()</code> streaming loop</td><td><a href="./../agents/goose/agentic-loop.html"><code>../agents/goose/agentic-loop.md</code></a></td></tr><tr><td><strong>Aider</strong></td><td>Edit → apply → lint → test loop</td><td><a href="./../agents/aider/agentic-loop.html"><code>../agents/aider/agentic-loop.md</code></a></td></tr></tbody></table>`,153)])])}const u=t(o,[["render",i]]);export{g as __pageData,u as default};
